SELECT FROM work_schedule_classes c LEFT JOIN work_schedule_class_breaks b ON c.class_id = b.class_id WHERE c.class_id IN
#{classId}
ORDER BY c.class_id ASC

SELECT EXISTS(
    SELECT 1 FROM work_schedule_classes
    WHERE name = #{name}
      AND class_id != #{classId}
)

SELECT EXISTS(
    SELECT 1 FROM work_schedule_classes
    WHERE class_code = #{classCode}
      AND class_id != #{classId}
)
